import { describe, expect, it } from 'vitest';
import type { TopologyAlphaStyleBackend } from '../src/style-transfer-topology-glue';
import { forkRaceFoldStyleTransfer } from '../src/forkRaceFoldStyleTransfer';
import { compositeStyleTransferFoldScore } from '../src/style-transfer-mesh-gate';

function makePlane(w: number, h: number, seed: number): Float32Array {
  const out = new Float32Array(w * h * 3);
  let s = seed >>> 0;
  const rand = () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff;
  };
  for (let i = 0; i < out.length; i++) out[i] = rand();
  return out;
}

describe('forkRaceFoldStyleTransfer', () => {
  it('runs multi-config style transfer and reports weighted survivors', async () => {
    const width = 16;
    const height = 16;
    const content = makePlane(width, height, 10);
    const style = makePlane(width, height, 20);

    const result = await forkRaceFoldStyleTransfer({
      content: { data: content, width, height, channels: 3 },
      style: { data: style, width, height, channels: 3 },
      configs: [
        { label: 'balanced', options: { method: 'classical', strength: 0.6 } },
        { label: 'aggressive', options: { method: 'classical', strength: 0.95 } },
      ],
    });

    expect(result.width).toBe(width);
    expect(result.height).toBe(height);
    expect(result.channels).toBe(3);
    expect(result.fold.survivors).toBe(2);
    expect(result.candidates).toHaveLength(2);
    expect(result.fold.totalWeight).toBeGreaterThan(0);
    const ranks = result.candidates.map((c) => c.rank).sort();
    expect(ranks).toEqual([0, 1]);
  });

  it('includes compositeFoldScore and penalizes low topology in fold ranking', async () => {
    const width = 12;
    const height = 12;
    const content = makePlane(width, height, 30);
    const style = makePlane(width, height, 31);
    const hi: TopologyAlphaStyleBackend = {
      async buildTopologyAlphaForStyle(req) {
        const a = new Float32Array(req.width * req.height);
        a.fill(1);
        return { alpha: a, provenanceFragment: { id: 'hi' } };
      },
    };
    const result = await forkRaceFoldStyleTransfer({
      content: { data: content, width, height, channels: 3 },
      style: { data: style, width, height, channels: 3 },
      topologyAlphaBackend: hi,
      meshFoldRankWeights: { topology: 2, depth: 0 },
      configs: [
        { label: 'mesh-a', options: { method: 'classical', strength: 0.85, meshGate: { enabled: true } } },
        { label: 'mesh-b', options: { method: 'classical', strength: 0.85, meshGate: { enabled: true } } },
      ],
    });
    for (const c of result.candidates) {
      expect(typeof c.compositeFoldScore).toBe('number');
      expect(Number.isFinite(c.compositeFoldScore!)).toBe(true);
      expect(c.meshFoldMetrics?.mean_topology_alpha).toBeGreaterThan(0.99);
    }
    const loTopo = {
      mean_topology_alpha: 0.1,
      mean_depth_confidence: 1,
      mean_effective_gate: 0.2,
      gate_violation_score: 0.8,
    };
    const hiTopo = {
      mean_topology_alpha: 1,
      mean_depth_confidence: 1,
      mean_effective_gate: 1,
      gate_violation_score: 0,
    };
    expect(compositeStyleTransferFoldScore(0.5, loTopo, { topology: 2 })).toBeGreaterThan(
      compositeStyleTransferFoldScore(0.5, hiTopo, { topology: 2 }),
    );
  });

  it('rejects all candidates with a strict ceiling', async () => {
    const width = 16;
    const height = 16;
    const content = makePlane(width, height, 77);
    const style = makePlane(width, height, 78);
    await expect(
      forkRaceFoldStyleTransfer({
        content: { data: content, width, height, channels: 3 },
        style: { data: style, width, height, channels: 3 },
        configs: [{ options: { method: 'classical', strength: 1 } }],
        ceiling: 1e-9,
      }),
    ).rejects.toThrow(/no candidates survived ceiling filter/);
  });
});
